INSERT INTO inventory.warehouse_assignment
    (tenant_id, user_id, warehouse_id,
     created_at, created_by, updated_at, updated_by, version)
SELECT '10000000-0000-4000-8000-000000000001'::uuid,
       users.user_id,
       warehouses.warehouse_id,
       '2026-07-13T00:00:00Z'::timestamptz,
       '11200000-0000-4000-8000-000000000004'::uuid,
       '2026-07-13T00:00:00Z'::timestamptz,
       '11200000-0000-4000-8000-000000000004'::uuid,
       0
  FROM (VALUES
          ('11200000-0000-4000-8000-000000000004'::uuid),
          ('11200000-0000-4000-8000-000000000005'::uuid)
       ) AS users(user_id)
 CROSS JOIN (VALUES
          ('35000000-0000-4000-8000-000000000001'::uuid),
          ('35000000-0000-4000-8000-000000000002'::uuid),
          ('35000000-0000-4000-8000-000000000003'::uuid),
          ('35000000-0000-4000-8000-000000000004'::uuid)
       ) AS warehouses(warehouse_id)
ON CONFLICT DO NOTHING;

